def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for k in range(1, 10):
                factor = ((1 - ratio) ** k) * (k * 0.7)
                if factor > 3:
                    factor /= (k + 2)
                if k % 3 == 0:
                    factor *= 0.9
                else:
                    factor *= 1.1 + (k*0.01)
                noise = np.sin(k * ratio * np.pi) * 0.5
                score += factor + noise
            if (capacity + item) % 5 == 0:
                score *= 0.92
            if score > 7:
                score /= 2.5
            if int(item*100) % 7 == 0:
                score += 1.3
        elif 0.2 <= ratio < 0.4:
            factorial = 1
            limit = int(capacity // 3) + 2
            for n in range(1, limit):
                factorial *= n
                if factorial > 1e6:
                    factorial %= 1200
                    break
            mod_factor = factorial % 600
            score += np.log1p(ratio * mod_factor)
            if (int(capacity) % 3 == 0) and (item % 0.2 == 0):
                score += 2.5
            else:
                score -= 0.8
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x * 1.5) % 1) * (x ** 1.3) * (np.cos(x*item) + 1)
            score += extra / 5
            if ratio > 0.35:
                score *= 1.2
        elif 0.4 <= ratio <= 0.7:
            for m in range(1, 7):
                increment = (ratio ** (m + 2)) * (m ** 2.5) / (m + 0.5)
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 5 + remainder * 1.1
            else:
                score -= remainder * 0.65
            if score < 0:
                score = abs(score) * 0.3 + 0.5
            if int(capacity) % 6 == 0:
                score *= 1.15
            if int(item * 10) % 5 == 0:
                score -= 0.7
        elif 0.7 < ratio <= 1.0:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.7) ** p) * (p ** 1.5)
            score = base_penalty * 8
            if capacity < item * 1.05:
                score += 8
            if (int(capacity * 8) % 6 == 0) and (int(item * 15) % 7 == 0):
                score -= 6
            if score < 0:
                score *= -1.3
                score += 1.5
            if ratio > 0.85:
                score *= 1.3
        elif 1.0 < ratio <= 1.5:
            penalty = 0
            diff = ratio - 1.0
            for q in range(1, 11):
                penalty += ((diff) ** q) * (q ** 2.2)
            score = penalty * 12
            if capacity < item * 1.3:
                score += 14
            if (int(capacity * 5) % 4 == 0) and (int(item * 9) % 3 == 0):
                score -= 7
            for z in range(1, 6):
                score += ((diff / (z + 1)) % 1) * (z * 1.4)
            if score < 0:
                score = abs(score) * 0.45 + 0.2
            if ratio > 1.3:
                score *= 0.9
        else:
            penalty = 0
            diff = ratio - 1.5
            for r in range(1, 12):
                penalty += ((diff) ** r) * (r ** 2.5)
            score = penalty * 20
            if capacity < item * 2:
                score += 20
            if (int(capacity * 9) % 5 == 0) and (int(item * 13) % 4 == 0):
                score -= 10
            for w in range(3, 7):
                score += ((diff / (w + 0.5)) % 1) * (w * 1.6)
            if score < 0:
                score = abs(score) * 0.5
            if ratio > 1.8:
                score *= 1.2
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.2)
            if ratio > 0.9:
                score *= 1.05
        elif capacity < 5:
            score *= 2.0
            if item < 1:
                score += 1.7
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        perc_85 = np.percentile(finite_priorities, 85)
        top_count = np.sum(finite_priorities > perc_85)
        fill_value = np.max(finite_priorities) * (15 + top_count * 1.5)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 1
    return priorities
